/*
 * Studio Kit — Design Tokens
 * Fonte da verdade: marca/design-guide.md
 * Dark é o tema principal. Light é override via classe .light ou [data-theme="light"].
 *
 * ─────────────────────────────────────────────────────────────────
 * RE-BRANDING POR CLIENTE — quais variáveis trocar
 * ─────────────────────────────────────────────────────────────────
 *
 * [OBRIGATÓRIO] Cor de acento — identidade visual do cliente
 *   --primary / --accent / --border / --ring / --input
 *   Valor: RGB separado por espaço. Ex: 255 87 51 (laranja #FF5733)
 *   Também ajuste --primary-foreground para garantir contraste.
 *
 * [OBRIGATÓRIO] Tipografia — personalidade da marca
 *   @import → URL da fonte no Google Fonts (ou self-hosted)
 *   --font-sans → nome da família principal
 *   --font-display → (opcional) família display/heading diferente
 *
 * [OPCIONAL] Fundo base — tom da marca
 *   --background / --background-secondary / --card
 *   Dark profundo (navy padrão): 8 20 36
 *   Dark grafite:                30 30 35
 *   Light branco frio:           248 250 252
 *   Light bege:                  250 247 242
 *
 * [OPCIONAL] Personalidade dos cantos
 *   --radius: 0rem (rígido) → 0.5rem (Studio default) → 1rem (amigável)
 *
 * [NÃO ALTERAR SEM NECESSIDADE]
 *   --foreground / --foreground-muted / --foreground-subtle
 *   --secondary / --muted / --destructive
 *   --border-alpha / --border-card-alpha / --border-subtle-alpha
 *   Estes derivam do fundo e do acento; raramente precisam de ajuste.
 *
 * Template de cliente → templates/astro-base/src/styles/tokens.css
 * ─────────────────────────────────────────────────────────────────
 */

@import url('https://fonts.googleapis.com/css2?family=Manrope:wght@400;500;600;700;800&display=swap');

/* ─── Dark (padrão) ─────────────────────────────────────────── */
:root {
  /* Fundos */
  --background:          8 20 36;      /* #081424 — navy profundo */
  --background-secondary: 3 12 23;    /* #030C17 — navy mais escuro */
  --card:                8 20 36;      /* rgba(8,20,36,0.92) com alpha */

  /* Texto */
  --foreground:          232 244 251;  /* rgba(232,244,251,0.92) */
  --foreground-muted:    232 244 251;  /* com alpha 0.45 */
  --foreground-subtle:   232 244 251;  /* com alpha 0.40 */

  /* Acento — cyan #00ADCF — TROCAR AQUI para a cor do cliente */
  --accent:              0 173 207;
  --accent-foreground:   232 244 251;

  /* shadcn semantic aliases */
  --primary:             0 173 207;    /* ← cor principal do cliente */
  --primary-foreground:  232 244 251;  /* ← branco ou preto, conforme contraste */
  --secondary:           3 12 23;
  --secondary-foreground: 232 244 251;
  --muted:               8 20 36;
  --muted-foreground:    232 244 251;
  --border:              0 173 207;    /* usado com alpha 0.18 via Tailwind */
  --input:               0 173 207;
  --ring:                0 173 207;
  --destructive:         239 68 68;
  --destructive-foreground: 232 244 251;

  /* Radius — TROCAR para personalidade do cliente */
  --radius: 0.5rem;                    /* moderado — contemporâneo, não arredondado demais */

  /* Alphas de borda — não alterar */
  --border-alpha:        0.18;
  --border-card-alpha:   0.25;
  --border-subtle-alpha: 0.10;

  /* Tipografia — TROCAR @import + --font-sans para a fonte do cliente */
  --font-sans: 'Manrope', system-ui, sans-serif;
}

/* ─── Light (override) ───────────────────────────────────────── */
.light,
[data-theme="light"] {
  --background:          248 250 252;  /* #F8FAFC — branco frio */
  --background-secondary: 241 245 249; /* #F1F5F9 */
  --card:                255 255 255;

  --foreground:          8 20 36;      /* navy como texto no light */
  --foreground-muted:    8 20 36;      /* com alpha 0.55 */
  --foreground-subtle:   8 20 36;      /* com alpha 0.40 */

  --primary:             0 173 207;    /* cyan permanece em ambos os temas */
  --primary-foreground:  255 255 255;
  --secondary:           241 245 249;
  --secondary-foreground: 8 20 36;
  --muted:               241 245 249;
  --muted-foreground:    8 20 36;
  --border:              0 173 207;
  --input:               0 173 207;
  --ring:                0 173 207;
}

/* ─── Base ───────────────────────────────────────────────────── */
*,
*::before,
*::after {
  border-color: rgb(var(--border) / var(--border-alpha, 0.18));
}

body {
  background-color: rgb(var(--background));
  color: rgb(var(--foreground) / 0.92);
  font-family: var(--font-sans);
  -webkit-font-smoothing: antialiased;
}
